// معالجة صفحة هيئة الخبراء
const inputData = $input.first();
const html = inputData && inputData.json ? (inputData.json.data || inputData.json.body || '') : '';
const knownLaws = [
  { id: 'labor', name: 'نظام العمل', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=1' },
  { id: 'companies', name: 'نظام الشركات', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=2' },
  { id: 'procurement', name: 'نظام المنافسات والمشتريات الحكومية', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=3' },
  { id: 'vat', name: 'نظام ضريبة القيمة المضافة', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=4' },
  { id: 'anticorruption', name: 'نظام مكافحة الفساد', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=5' }
];
const fallback = knownLaws.map(function(law) {
  return { json: { source: 'boe_fallback', source_name: 'هيئة الخبراء بمجلس الوزراء', law_id: law.id, law_name: law.name, url: law.url, fetched_at: new Date().toISOString() } };
});
if (html.length < 100) {
  return fallback;
}
const linkRegex = /href="([^"]*LawDetails[^"]*)"/gi;
const links = [];
let match;
while ((match = linkRegex.exec(html)) !== null) {
  links.push({ json: { source: 'boe', source_name: 'هيئة الخبراء بمجلس الوزراء', url: match[1].startsWith('http') ? match[1] : 'https://www.boe.gov.sa' + match[1], fetched_at: new Date().toISOString() } });
}
return links.length > 0 ? links.slice(0, 50) : fallback;

// معالجة صفحة أم القرى
const inputData = $input.first();
const html = inputData && inputData.json ? (inputData.json.data || inputData.json.body || '') : '';
const today = new Date();
const fallback = [0,1,2,3].map(function(i) {
  const d = new Date(today);
  d.setDate(today.getDate() - i*7);
  return { json: { source: 'uqn_fallback', source_name: 'جريدة أم القرى الرسمية', url: 'https://www.uqn.gov.sa/issues', approximate_date: d.toISOString().split('T')[0], fetched_at: new Date().toISOString(), type: 'official_gazette' } };
});
if (html.length < 100) {
  return fallback;
}
const issueRegex = /href="([^"]*issue[^"]*)"/gi;
const issues = [];
let match;
while ((match = issueRegex.exec(html)) !== null) {
  issues.push({ json: { source: 'uqn', source_name: 'جريدة أم القرى الرسمية', url: match[1].startsWith('http') ? match[1] : 'https://www.uqn.gov.sa' + match[1], fetched_at: new Date().toISOString(), type: 'official_gazette' } });
}
return issues.length > 0 ? issues.slice(0, 10) : fallback;

// تنظيف النص المستخرج وتقسيمه إلى chunks
const items = $input.all();
const results = [];

for (const item of items) {
  const rawText = item.json.data || item.json.body || '';
  const source = item.json.source || 'unknown';
  const url = item.json.url || '';
  const lawName = item.json.law_name || item.json.name || 'نظام غير محدد';

  if (!rawText || rawText.length < 100) {
    continue; // تخطي الوثائق الفارغة
  }

  // تنظيف النص
  const cleanText = rawText
    .replace(/<[^>]+>/g, ' ')  // إزالة HTML
    .replace(/\s+/g, ' ')       // توحيد المسافات
    .trim();

  // تقسيم إلى chunks بحجم 1000 حرف مع تداخل 200 حرف
  const chunkSize = 1000;
  const overlap = 200;
  const chunks = [];

  for (let i = 0; i < cleanText.length; i += (chunkSize - overlap)) {
    const chunk = cleanText.substring(i, i + chunkSize);
    if (chunk.length > 100) { // تجاهل الـ chunks الصغيرة جداً
      chunks.push({
        text: chunk,
        chunk_index: chunks.length,
        total_chunks: Math.ceil(cleanText.length / (chunkSize - overlap)),
        source: source,
        source_name: item.json.source_name || source,
        url: url,
        law_name: lawName,
        doc_id: `${source}_${Buffer.from(url).toString('base64').substring(0, 20)}`,
        fetched_at: item.json.fetched_at || new Date().toISOString(),
        char_count: chunk.length
      });
    }
  }

  results.push(...chunks);
}

return results;

// التحقق من وجود الوثيقة في ChromaDB قبل الإضافة
const items = $input.all();
const results = [];

for (const item of items) {
  const embedding = item.json.embedding;

  if (!embedding || !Array.isArray(embedding) || embedding.length === 0) {
    console.log('تخطي: لا يوجد embedding لـ', item.json.doc_id);
    continue;
  }

  results.push({
    ...item.json,
    embedding: embedding,
    has_embedding: true,
    processed_at: new Date().toISOString()
  });
}

return results;

// إنشاء تقرير نهائي بنتائج المزامنة
const items = $input.all();

const stats = {
  total_processed: items.length,
  successful: items.filter(i => i.json.status === 200 || i.json.upserted_count > 0).length,
  failed: items.filter(i => i.json.error).length,
  sources: {
    boe: items.filter(i => i.json.source === 'boe' || i.json.source === 'boe_fallback').length,
    uqn: items.filter(i => i.json.source === 'uqn' || i.json.source === 'uqn_fallback').length
  },
  run_date: new Date().toISOString(),
  collection: 'saleh_legal_knowledge'
};

const report = `
📊 تقرير مزامنة القوانين السعودية
=====================================
📅 تاريخ التشغيل: ${stats.run_date}
📦 إجمالي الـ Chunks المعالجة: ${stats.total_processed}
✅ نجح: ${stats.successful}
❌ فشل: ${stats.failed}

📚 المصادر:
  - هيئة الخبراء (BOE): ${stats.sources.boe} chunk
  - أم القرى (UQN): ${stats.sources.uqn} chunk

💾 قاعدة البيانات: ChromaDB - مجموعة '${stats.collection}'
=====================================
`;

return [{ json: { report, stats } }];
